# @cctt_verify {"v":2,"sym":"sympy.polys.tests.test_monomials.test_Monomial","kind":"function","src_hash":"a957ace7aaa4a677","in":{"base":"Any"},"out":{"base":"Any","pred":"m.as_expr() == x ** 3 * y ** 4 * z and n.as_expr() == x ** 1 * y ** 2 and m.as_expr(a, b, c) == a ** 3 * b ** 4 * c and n.as_expr(a, b, c) == a ** 1 * b ** 2 and m.exponents == (3, 4, 1) and m.gens == (x, y, z) and n.exponents == (1, 2, 0) and n.gens == (x, y, z) and m == (3, 4, 1) and n != (3, 4, 1) and m != (1, 2, 0) and n == (1, 2, 0) and (m == 1) is False and m[0] == m[-3] == 3 and m[1] == m[-2] == 4 and m[2] == m[-1] == 1 and n[0] == n[-3] == 1 and n[1] == n[-2] == 2 and n[2] == n[-1] == 0 and m[:2] == (3, 4) and n[:2] == (1, 2) and m * n == Monomial((4, 6, 1)) and m / n == Monomial((2, 2, 1)) and m * (1, 2, 0) == Monomial((4, 6, 1)) and m / (1, 2, 0) == Monomial((2, 2, 1)) and m.gcd(n) == Monomial((1, 2, 0)) and m.lcm(n) == Monomial((3, 4, 1)) and m.gcd((1, 2, 0)) == Monomial((1, 2, 0)) and m.lcm((1, 2, 0)) == Monomial((3, 4, 1)) and m ** 0 == Monomial((0, 0, 0)) and m ** 1 == m and m ** 2 == Monomial((6, 8, 2)) and m ** 3 == Monomial((9, 12, 3)) and str(mm) == 'Monomial((1, 2, 3))' and str(m) == 'x**3*y**4*z**1' and _a == m ** n"},"spec":{"lhs":"test_Monomial()","rhs":"test_Monomial produces the expected output","over":{"base":"Any"},"name":"test_Monomial_correct"},"guarantee":"test_Monomial produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.polys.tests.test_monomials.test_Monomial_correct","statement":"Path(test_Monomial(x), test_Monomial produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"1fc421e464cc076e"}
def test_Monomial():
    m = Monomial((3, 4, 1), (x, y, z))
    n = Monomial((1, 2, 0), (x, y, z))

    assert m.as_expr() == x**3*y**4*z
    assert n.as_expr() == x**1*y**2

    assert m.as_expr(a, b, c) == a**3*b**4*c
    assert n.as_expr(a, b, c) == a**1*b**2

    assert m.exponents == (3, 4, 1)
    assert m.gens == (x, y, z)

    assert n.exponents == (1, 2, 0)
    assert n.gens == (x, y, z)

    assert m == (3, 4, 1)
    assert n != (3, 4, 1)
    assert m != (1, 2, 0)
    assert n == (1, 2, 0)
    assert (m == 1) is False

    assert m[0] == m[-3] == 3
    assert m[1] == m[-2] == 4
    assert m[2] == m[-1] == 1

    assert n[0] == n[-3] == 1
    assert n[1] == n[-2] == 2
    assert n[2] == n[-1] == 0

    assert m[:2] == (3, 4)
    assert n[:2] == (1, 2)

    assert m*n == Monomial((4, 6, 1))
    assert m/n == Monomial((2, 2, 1))

    assert m*(1, 2, 0) == Monomial((4, 6, 1))
    assert m/(1, 2, 0) == Monomial((2, 2, 1))

    assert m.gcd(n) == Monomial((1, 2, 0))
    assert m.lcm(n) == Monomial((3, 4, 1))

    assert m.gcd((1, 2, 0)) == Monomial((1, 2, 0))
    assert m.lcm((1, 2, 0)) == Monomial((3, 4, 1))

    assert m**0 == Monomial((0, 0, 0))
    assert m**1 == m
    assert m**2 == Monomial((6, 8, 2))
    assert m**3 == Monomial((9, 12, 3))
    _a = Monomial((0, 0, 0))
    for n in range(10):
        assert _a == m**n
        _a *= m

    raises(ExactQuotientFailed, lambda: m/Monomial((5, 2, 0)))

    mm = Monomial((1, 2, 3))
    raises(ValueError, lambda: mm.as_expr())
    assert str(mm) == 'Monomial((1, 2, 3))'
    assert str(m) == 'x**3*y**4*z**1'
    raises(NotImplementedError, lambda: m*1)
    raises(NotImplementedError, lambda: m/1)
    raises(ValueError, lambda: m**-1)
    raises(TypeError, lambda: m.gcd(3))
    raises(TypeError, lambda: m.lcm(3))
